/**
 * LiveScannerPage — Real-time scanning/signals dashboard.
 * Designed to feel alive: pulsing indicators, auto-scrolling signal feed,
 * strategy heatmap, top movers, and live connection status.
 *
 * Data sources:
 *   - Polling: /api/signals/latest (every 5s), /api/scanners/signals/live (every 30s)
 *   - SSE:    /api/realtime/stream (EventSource, graceful fallback to polling)
 */
import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useSearchParams } from 'react-router-dom';
import { api } from '../utils/api';
import { getApiBase } from '../utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import { tokens } from '../styles/tokens';
import s from './LiveScannerPage.module.css';

const C = {
  green: tokens.color.green,
  red: tokens.color.red,
  blue: tokens.color.blue,
  amber: tokens.color.amber,
  purple: tokens.color.purple,
  cyan: tokens.color.cyan,
  text: tokens.color.text,
  textSec: tokens.color.textSecondary,
  surface: tokens.color.surface,
  surface2: tokens.color.surfaceHover,
  border: tokens.color.border,
};

// ── Helpers ──────────────────────────────────────────────────────────────

function formatTime(dateStr, epoch) {
  if (epoch && epoch > 0) {
    const d = new Date(epoch * 1000);
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  }
  if (dateStr) {
    const d = new Date(dateStr);
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  }
  const now = new Date();
  return now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
}

function confidenceColor(pct) {
  if (pct >= 70) return C.green;
  if (pct >= 50) return C.amber;
  return C.red;
}

function getMarketStatus() {
  const now = new Date();
  const h = now.getUTCHours();
  const d = now.getUTCDay();
  // Rough market hours check (US Eastern ~13:30-20:00 UTC, crypto 24/7)
  if (d === 0 || d === 6) {
    return { label: 'WEEKEND', color: C.amber, sub: 'Crypto active' };
  }
  if (h >= 13 && h < 20) {
    return { label: 'MARKET OPEN', color: C.green, sub: 'US session' };
  }
  if (h >= 7 && h < 16) {
    return { label: 'EU SESSION', color: C.blue, sub: 'LSE / Xetra' };
  }
  if (h >= 0 && h < 8) {
    return { label: 'ASIA SESSION', color: C.purple, sub: 'TSE / HKEX' };
  }
  return { label: 'AFTER HOURS', color: C.amber, sub: 'Pre/post market' };
}

// ── Component ────────────────────────────────────────────────────────────

export default function LiveScannerPage() {
  usePageTitle('Live Scanner');

  // Watchlist pre-filter from ?symbols= query param
  const [searchParams] = useSearchParams();
  const watchlistSymbols = useMemo(() => {
    const raw = searchParams.get('symbols');
    if (!raw) return null;
    const arr = raw.split(',').map(s => s.trim().toUpperCase()).filter(Boolean);
    return arr.length > 0 ? new Set(arr) : null;
  }, [searchParams]);

  // Signal feed state
  const [signals, setSignals] = useState([]);
  const [newSignalIds, setNewSignalIds] = useState(new Set());
  const [totalToday, setTotalToday] = useState(0);
  const [activeStrategies, setActiveStrategies] = useState(0);
  const [lastScanEpoch, setLastScanEpoch] = useState(Date.now() / 1000);
  const [secondsSinceScan, setSecondsSinceScan] = useState(0);

  // Top movers
  const [topMovers, setTopMovers] = useState([]);

  // Strategy heatmap
  const [strategyMap, setStrategyMap] = useState({});
  const [selectedStrategy, setSelectedStrategy] = useState(null);

  // Connection status
  const [connectionStatus, setConnectionStatus] = useState('connecting'); // 'connected' | 'polling' | 'disconnected'
  const sseRef = useRef(null);
  const feedRef = useRef(null);
  const prevSignalKeysRef = useRef(new Set());

  // Direction filter
  const [dirFilter, setDirFilter] = useState('all'); // 'all' | 'long' | 'short'

  // ── SSE Connection ──
  useEffect(() => {
    const API_BASE = getApiBase();
    let es;
    try {
      es = new EventSource(`${API_BASE}/realtime/stream`);
      sseRef.current = es;

      es.onopen = () => setConnectionStatus('connected');

      es.addEventListener('signal', (ev) => {
        try {
          const sig = JSON.parse(ev.data);
          setSignals(prev => {
            const updated = [sig, ...prev].slice(0, 200);
            return updated;
          });
          setNewSignalIds(prev => {
            const next = new Set(prev);
            next.add(`${sig.symbol}-${sig.strategy}-${Date.now()}`);
            return next;
          });
          setLastScanEpoch(Date.now() / 1000);
          setTotalToday(prev => prev + 1);
        } catch { /* ignore parse errors */ }
      });

      es.addEventListener('heartbeat', () => {
        setLastScanEpoch(Date.now() / 1000);
      });

      es.onerror = () => {
        setConnectionStatus('polling');
        es.close();
      };
    } catch {
      setConnectionStatus('polling');
    }

    return () => {
      if (es) es.close();
    };
  }, []);

  // ── Polling fallback: fetch signals every 5s ──
  const fetchSignals = useCallback(async () => {
    const data = await api('/signals/latest?promoted_only=true');
    if (!data) return;
    const arr = Array.isArray(data.signals) ? data.signals : [];

    // Detect new signals
    const currentKeys = new Set(arr.map(sig => `${sig.symbol}-${sig.strategy}-${sig.direction}`));
    const newKeys = new Set();
    currentKeys.forEach(k => {
      if (!prevSignalKeysRef.current.has(k)) newKeys.add(k);
    });
    prevSignalKeysRef.current = currentKeys;

    setSignals(arr);
    setTotalToday(data.count || arr.length);
    if (data.signals_generated_at) {
      setLastScanEpoch(data.signals_generated_at);
    }

    // Mark new signals
    if (newKeys.size > 0) {
      setNewSignalIds(newKeys);
      setTimeout(() => setNewSignalIds(new Set()), 2000);
    }

    // Build strategy map from signals
    const sMap = {};
    arr.forEach(sig => {
      const strat = sig.strategy || 'Unknown';
      if (!sMap[strat]) sMap[strat] = { count: 0, direction: sig.direction };
      sMap[strat].count += 1;
    });
    setStrategyMap(sMap);
    setActiveStrategies(Object.keys(sMap).length);

    // Build top movers from signals
    const symbolMap = {};
    arr.forEach(sig => {
      const sym = sig.symbol;
      if (!symbolMap[sym]) symbolMap[sym] = { symbol: sym, count: 0, direction: sig.direction, confidence: sig.confidence || 0 };
      symbolMap[sym].count += 1;
      symbolMap[sym].confidence = Math.max(symbolMap[sym].confidence, sig.confidence || 0);
    });
    const movers = Object.values(symbolMap).sort((a, b) => b.count - a.count).slice(0, 10);
    setTopMovers(movers);
  }, []);

  useEffect(() => {
    fetchSignals();
    const iv = setInterval(fetchSignals, 5000);
    return () => clearInterval(iv);
  }, [fetchSignals]);

  // ── Seconds since scan countdown ──
  useEffect(() => {
    const iv = setInterval(() => {
      const elapsed = Math.floor(Date.now() / 1000 - lastScanEpoch);
      setSecondsSinceScan(Math.max(0, elapsed));
    }, 1000);
    return () => clearInterval(iv);
  }, [lastScanEpoch]);

  // ── Clear new-signal highlight after 2s ──
  useEffect(() => {
    if (newSignalIds.size > 0) {
      const t = setTimeout(() => setNewSignalIds(new Set()), 2000);
      return () => clearTimeout(t);
    }
  }, [newSignalIds]);

  // ── Auto-scroll feed ──
  useEffect(() => {
    if (feedRef.current && signals.length > 0) {
      feedRef.current.scrollTop = 0;
    }
  }, [signals.length]);

  // ── Filtered signals ──
  const filteredSignals = useMemo(() => {
    let out = signals;
    // Pre-filter to watchlist symbols if navigated from watchlist
    if (watchlistSymbols) {
      out = out.filter(sig => watchlistSymbols.has((sig.symbol || '').toUpperCase()));
    }
    if (dirFilter === 'long') {
      out = out.filter(sig => {
        const d = sig.direction?.toLowerCase();
        return d === 'long' || d === 'buy';
      });
    } else if (dirFilter === 'short') {
      out = out.filter(sig => {
        const d = sig.direction?.toLowerCase();
        return d === 'short' || d === 'sell';
      });
    }
    if (selectedStrategy) {
      out = out.filter(sig => sig.strategy === selectedStrategy);
    }
    return out;
  }, [signals, dirFilter, selectedStrategy, watchlistSymbols]);

  // ── Derived stats ──
  const signalsPerHour = useMemo(() => {
    if (totalToday === 0) return 0;
    const now = new Date();
    const hoursSinceMidnight = now.getHours() + now.getMinutes() / 60;
    if (hoursSinceMidnight < 0.1) return totalToday;
    return Math.round(totalToday / hoursSinceMidnight);
  }, [totalToday]);

  const mostActiveStrategy = useMemo(() => {
    let best = null;
    let bestCount = 0;
    Object.entries(strategyMap).forEach(([name, data]) => {
      if (data.count > bestCount) {
        bestCount = data.count;
        best = name;
      }
    });
    return best ? best.replace(/_/g, ' ') : '--';
  }, [strategyMap]);

  const marketStatus = useMemo(() => getMarketStatus(), []);

  // ── Sorted strategy list for heatmap ──
  const sortedStrategies = useMemo(() => {
    return Object.entries(strategyMap)
      .map(([name, data]) => ({ name, count: data.count, direction: data.direction }))
      .sort((a, b) => b.count - a.count);
  }, [strategyMap]);

  const maxMoverCount = topMovers.length > 0 ? topMovers[0].count : 1;

  // ── Render ──
  return (
    <div className={s.page}>
      {/* ═══ LIVE ACTIVITY BAR ═══ */}
      <div className={s.activityBar}>
        <div className={s.liveBadge}>
          <span className={s.liveDot} />
          LIVE
        </div>

        <div className={s.activityStat}>
          <span>Last scan:</span>
          <span className={s.activityStatValue}>
            {secondsSinceScan}s ago
          </span>
        </div>

        <div className={s.activityStat}>
          <span className={s.activityStatHighlight}>{totalToday}</span>
          <span>signals today</span>
        </div>

        <div className={s.activityStat}>
          <span className={s.activityStatHighlight}>{activeStrategies}</span>
          <span>strategies active</span>
        </div>

        <div className={s.activitySpacer} />

        {/* Connection status */}
        <div className={s.activityStat}>
          <span className={`${s.connectionDot} ${
            connectionStatus === 'connected' ? s.connectionDotConnected :
            connectionStatus === 'polling' ? s.connectionDotPolling :
            s.connectionDotDisconnected
          }`} />
          <span style={{ fontSize: 10 }}>
            {connectionStatus === 'connected' ? 'SSE' :
             connectionStatus === 'polling' ? 'Polling' : 'Offline'}
          </span>
        </div>

        {/* Market status */}
        <div className={s.marketBadge} style={{
          background: `color-mix(in srgb, ${marketStatus.color} 10%, transparent)`,
          color: marketStatus.color,
          border: `1px solid color-mix(in srgb, ${marketStatus.color} 20%, transparent)`,
        }}>
          <span style={{
            width: 5, height: 5, borderRadius: '50%',
            background: marketStatus.color, display: 'inline-block',
          }} />
          {marketStatus.label}
        </div>
      </div>

      {/* ═══ WATCHLIST FILTER BANNER ═══ */}
      {watchlistSymbols && (
        <div style={{
          padding: '6px 16px',
          background: `color-mix(in srgb, ${C.amber} 8%, transparent)`,
          border: `1px solid color-mix(in srgb, ${C.amber} 20%, transparent)`,
          borderRadius: 6,
          fontSize: 11,
          fontFamily: tokens.font.mono,
          color: C.amber,
          display: 'flex',
          alignItems: 'center',
          gap: 8,
        }}>
          <span style={{ fontWeight: 700 }}>WATCHLIST FILTER</span>
          <span style={{ opacity: 0.75 }}>
            Showing signals for {watchlistSymbols.size} symbol{watchlistSymbols.size !== 1 ? 's' : ''}:
            {' '}{[...watchlistSymbols].slice(0, 10).join(', ')}{watchlistSymbols.size > 10 ? ` +${watchlistSymbols.size - 10} more` : ''}
          </span>
        </div>
      )}

      {/* ═══ MAIN CONTENT ═══ */}
      <div className={s.mainContent}>

        {/* ── SIGNAL FEED (left 60%) ── */}
        <div className={s.feedPanel}>
          <div className={s.feedHeader}>
            <div className={s.feedTitle}>
              Signal Feed
              <span className={s.feedCount}>{filteredSignals.length}</span>
            </div>
            <div className={s.feedFilter}>
              <button
                className={`${s.filterBtn} ${dirFilter === 'all' ? s.filterBtnActive : ''}`}
                onClick={() => setDirFilter('all')}
              >
                All
              </button>
              <button
                className={`${s.filterBtn} ${dirFilter === 'long' ? s.filterBtnActive : ''}`}
                onClick={() => setDirFilter('long')}
                style={dirFilter === 'long' ? { color: C.green, borderColor: `color-mix(in srgb, ${C.green} 25%, transparent)`, background: `color-mix(in srgb, ${C.green} 8%, transparent)` } : {}}
              >
                Long
              </button>
              <button
                className={`${s.filterBtn} ${dirFilter === 'short' ? s.filterBtnActive : ''}`}
                onClick={() => setDirFilter('short')}
                style={dirFilter === 'short' ? { color: C.red, borderColor: `color-mix(in srgb, ${C.red} 25%, transparent)`, background: `color-mix(in srgb, ${C.red} 8%, transparent)` } : {}}
              >
                Short
              </button>
              {selectedStrategy && (
                <button
                  className={s.filterBtn}
                  onClick={() => setSelectedStrategy(null)}
                  style={{ color: C.blue, borderColor: `color-mix(in srgb, ${C.blue} 25%, transparent)` }}
                >
                  {selectedStrategy.replace(/_/g, ' ')} x
                </button>
              )}
            </div>
          </div>

          <div className={s.feedList} ref={feedRef}>
            {filteredSignals.length === 0 ? (
              <div className={s.emptyFeed}>
                <div className={s.emptyIcon}>
                  <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                    <circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" />
                  </svg>
                </div>
                <div>Waiting for signals...</div>
                <div style={{ fontSize: 11, opacity: 0.6 }}>
                  Signals update every 5 seconds during market hours
                </div>
              </div>
            ) : (
              <AnimatePresence initial={false}>
                {filteredSignals.slice(0, 100).map((sig, idx) => {
                  const isLong = sig.direction?.toLowerCase() === 'long' || sig.direction?.toLowerCase() === 'buy';
                  const conf = Math.round((sig.confidence || 0) * 100);
                  const sigKey = `${sig.symbol}-${sig.strategy}-${sig.direction}`;
                  const isNew = newSignalIds.has(sigKey);

                  return (
                    <motion.div
                      key={`${sigKey}-${idx}`}
                      className={`${s.signalCard} ${isNew ? s.signalCardNew : ''}`}
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ duration: 0.2, delay: idx * 0.01 }}
                    >
                      <span className={s.signalTime}>
                        {formatTime(sig.date, sig.generated_at)}
                      </span>

                      <span className={s.signalSymbol}>
                        {sig.symbol}
                      </span>

                      <span className={s.signalStrategy}>
                        {(sig.strategy || '').replace(/_/g, ' ')}
                      </span>

                      <span className={`${s.signalDirection} ${isLong ? s.signalLong : s.signalShort}`}>
                        {isLong ? 'LONG' : 'SHORT'}
                      </span>

                      <span className={s.signalConfidence}>
                        <span className={s.confidenceTrack}>
                          <span
                            className={s.confidenceFill}
                            style={{
                              width: `${Math.min(100, conf)}%`,
                              background: confidenceColor(conf),
                            }}
                          />
                        </span>
                        <span className={s.confidenceLabel} style={{ color: confidenceColor(conf) }}>
                          {conf}%
                        </span>
                      </span>

                      <span className={s.signalRegion}>
                        {sig.region?.toUpperCase() || ''}
                      </span>
                    </motion.div>
                  );
                })}
              </AnimatePresence>
            )}
          </div>
        </div>

        {/* ── RIGHT SIDEBAR ── */}
        <div className={s.sidePanel}>

          {/* Top Movers */}
          <div className={s.topMoversSection}>
            <div className={s.sectionHeader}>
              <div className={s.sectionTitle}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <polyline points="23 6 13.5 15.5 8.5 10.5 1 18" />
                  <polyline points="17 6 23 6 23 12" />
                </svg>
                Top Movers
              </div>
              <span className={s.sectionMeta}>by signal count</span>
            </div>

            <div className={s.moversList}>
              {topMovers.length === 0 ? (
                <div style={{ padding: '20px 16px', textAlign: 'center', fontSize: 12, color: C.textSec }}>
                  Waiting for data...
                </div>
              ) : (
                topMovers.map((mover, i) => {
                  const isLong = mover.direction?.toLowerCase() === 'long' || mover.direction?.toLowerCase() === 'buy';
                  const barColor = isLong ? C.green : C.red;
                  return (
                    <div key={mover.symbol} className={s.moverRow}>
                      <span className={s.moverRank}>{i + 1}</span>
                      <span className={s.moverSymbol}>{mover.symbol}</span>
                      <div className={s.moverBar}>
                        <div
                          className={s.moverBarFill}
                          style={{
                            width: `${(mover.count / maxMoverCount) * 100}%`,
                            background: barColor,
                          }}
                        />
                      </div>
                      <span className={s.moverCount} style={{ color: barColor }}>
                        {mover.count}
                      </span>
                      <span className={s.moverDirection} style={{
                        background: `color-mix(in srgb, ${barColor} 12%, transparent)`,
                        color: barColor,
                      }}>
                        {isLong ? 'L' : 'S'}
                      </span>
                    </div>
                  );
                })
              )}
            </div>
          </div>

          {/* Strategy Heatmap */}
          <div className={s.heatmapSection}>
            <div className={s.sectionHeader}>
              <div className={s.sectionTitle}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <rect x="3" y="3" width="7" height="7" /><rect x="14" y="3" width="7" height="7" />
                  <rect x="14" y="14" width="7" height="7" /><rect x="3" y="14" width="7" height="7" />
                </svg>
                Strategy Heatmap
              </div>
              <span className={s.sectionMeta}>
                {sortedStrategies.length} active
              </span>
            </div>

            <div className={s.heatmapGrid}>
              {sortedStrategies.length === 0 ? (
                <div style={{ gridColumn: '1 / -1', padding: '20px', textAlign: 'center', fontSize: 12, color: C.textSec }}>
                  Waiting for strategy data...
                </div>
              ) : (
                sortedStrategies.map(strat => {
                  const isActive = strat.count > 0;
                  const intensity = Math.min(1, strat.count / Math.max(1, sortedStrategies[0]?.count || 1));
                  const cellColor = isActive ? C.green : C.textSec;
                  const isSelected = selectedStrategy === strat.name;

                  return (
                    <div
                      key={strat.name}
                      className={`${s.heatmapCell} ${isActive ? s.heatmapCellActive : ''} ${isSelected ? s.heatmapCellSelected : ''}`}
                      style={{
                        background: isActive
                          ? `color-mix(in srgb, ${C.green} ${Math.round(intensity * 12)}%, transparent)`
                          : 'transparent',
                      }}
                      onClick={() => setSelectedStrategy(isSelected ? null : strat.name)}
                      title={`${strat.name.replace(/_/g, ' ')}: ${strat.count} signals`}
                    >
                      <span className={s.heatmapName}>
                        {strat.name.replace(/_/g, ' ')}
                      </span>
                      <span className={s.heatmapCount} style={{ color: cellColor }}>
                        {strat.count}
                      </span>
                      <span
                        className={s.heatmapDot}
                        style={{
                          background: isActive ? C.green : `color-mix(in srgb, ${C.textSec} 30%, transparent)`,
                          boxShadow: isActive ? `0 0 4px ${C.green}` : 'none',
                          animation: isActive ? 'livePulse 2s ease-in-out infinite' : 'none',
                        }}
                      />
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>
      </div>

      {/* ═══ STATS BAR (bottom) ═══ */}
      <div className={s.statsBar}>
        <div className={s.statsBarItem}>
          <span className={s.statsBarLabel}>Signals/hr</span>
          <span className={s.statsBarValue}>{signalsPerHour}</span>
        </div>

        <div className={s.statsBarItem}>
          <span className={s.statsBarLabel}>Most active</span>
          <span className={s.statsBarValueGreen}>{mostActiveStrategy}</span>
        </div>

        <div className={s.statsBarItem}>
          <span className={s.statsBarLabel}>Market</span>
          <span className={s.statsBarValueAmber}>{marketStatus.label}</span>
        </div>

        <div className={s.statsBarItem}>
          <span className={s.statsBarLabel}>Long / Short</span>
          <span className={s.statsBarValue}>
            <span style={{ color: C.green }}>
              {signals.filter(sig => {
                const d = sig.direction?.toLowerCase();
                return d === 'long' || d === 'buy';
              }).length}
            </span>
            {' / '}
            <span style={{ color: C.red }}>
              {signals.filter(sig => {
                const d = sig.direction?.toLowerCase();
                return d === 'short' || d === 'sell';
              }).length}
            </span>
          </span>
        </div>

        <div style={{ flex: 1 }} />

        <div className={s.statsBarItem}>
          <span className={s.statsBarLabel}>Feed</span>
          <span className={s.statsBarValue}>{filteredSignals.length} showing</span>
        </div>
      </div>
    </div>
  );
}
